import FormularioCampesenaCompleto from './FormularioCampesenaCompleto';
import Swal from 'sweetalert2';

const CrearOferta = () => {
  const [modo, setModo] = useState(null);
  const [loading, setLoading] = useState(false);
  const [mostrarFormularioEmpresa, setMostrarFormularioEmpresa] = useState(false);
  const [instructoresVisibles, setInstructoresVisibles] = useState({
    primerInstructor: '',
    segundoInstructor: ''
  });
  const [tiposProgramaIds, setTiposProgramaIds] = useState({ regular: '', campesena: '' });

  const [formData, setFormData] = useState({
    programa_formacion: '',
    modalidad: '',
    tipo_oferta: '',
    cupo_maximo: '',
    ambiente: { nombre: '' },
    fechas: { inicio: '', fin: '' },
    ubicacion: { departamento: 'Cauca', municipio: '', direccion: '' },
    empresa_solicitante: '',
    subsector_economico: { nombre: '' },
    programa_especial: '',
    convenio: { nombre: '' },
    horario: { hora_inicio: '08:00', hora_fin: '12:00', dias: [] },
    firma_digital_pdf: null,
    carta_pdf: null
  });

  const [programas, setProgramas] = useState([]);
  const [modalidades, setModalidades] = useState([]);
  const [tiposPrograma, setTiposPrograma] = useState([]);
  const [tiposOferta, setTiposOferta] = useState([]);
  const [municipios, setMunicipios] = useState([]);
  const [programasEspeciales, setProgramasEspeciales] = useState([]);
  const [empresas, setEmpresas] = useState([]);

  const [nuevaEmpresa, setNuevaEmpresa] = useState({
    nombre: '', nit: '', fecha_creacion: '', tipo_empresa: 'Privada', direccion: '',
    representante_legal: { nombre_completo: '', documento_identidad: '', telefono: '', correo: '' },
    contacto: { nombre_completo: '', cargo: '', telefono: '', correo: '' },
    numero_empleados: ''
  });

  useEffect(() => { cargarDatosIniciales(); }, []);

  const cargarDatosIniciales = async () => {
    try {
      const [programasRes, modalidadesRes, tiposProgramaRes, tiposOfertaRes, municipiosRes, programasEspecialesRes, empresasRes] = await Promise.all([
        api.get('/programas-formacion'), api.get('/modalidades'), api.get('/tipos-programa'),
        api.get('/tipos-oferta'), api.get('/municipios'), api.get('/programas-especiales'), api.get('/empresas')
      ]);
      setProgramas(programasRes.data.data || []);
      setModalidades(modalidadesRes.data.data || []);
      setTiposPrograma(tiposProgramaRes.data.data || []);
      setTiposOferta(tiposOfertaRes.data.data || []);
      setMunicipios(municipiosRes.data.data || []);
      setProgramasEspeciales(programasEspecialesRes.data.data || []);
      setEmpresas(empresasRes.data.data || []);
    } catch (error) {
      console.error('Error cargando datos:', error);
    }
  };

  useEffect(() => {
    if (tiposPrograma.length > 0) {
      const regular = tiposPrograma.find(t => t.nombre === 'Regular');
      const campesena = tiposPrograma.find(t => t.nombre === 'Campesena');
      setTiposProgramaIds({ regular: regular?._id || '', campesena: campesena?._id || '' });
    }
  }, [tiposPrograma]);

  useEffect(() => {
    if (modo === 'campesena' && formData.tipo_programa) {
      const tipoSeleccionado = tiposPrograma.find(t => t._id === formData.tipo_programa);
      if (tipoSeleccionado) {
        const instructores = { 'Técnico': { primero: 'Empresarial', segundo: 'Popular' }, 'Empresarial': { primero: 'Técnico', segundo: 'Popular' }, 'Popular': { primero: 'Técnico', segundo: 'Empresarial' } };
        setInstructoresVisibles(instructores[tipoSeleccionado.nombre] || { primero: '', segundo: '' });
      }
    }
  }, [formData.tipo_programa, tiposPrograma, modo]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({ ...formData, [parent]: { ...formData[parent], [child]: value } });
    } else {
      setFormData({ ...formData, [name]: value });
    }
  };

  const handleDiaChange = (e) => {
    const { value, checked } = e.target;
    setFormData({
      ...formData,
      horario: { ...formData.horario, dias: checked ? [...formData.horario.dias, value] : formData.horario.dias.filter(d => d !== value) }
    });
  };

  const handleFileChange = (e) => {
    const { name, files } = e.target;
    if (files && files[0]) {
      if (files[0].type !== 'application/pdf') { Swal.fire({ icon: 'error', title: 'Formato incorrecto', text: 'Solo se permiten archivos PDF', timer: 3000, showConfirmButton: false }); return; }
      if (files[0].size > 5 * 1024 * 1024) { Swal.fire({ icon: 'error', title: 'Archivo muy grande', text: 'El archivo no puede superar los 5MB', timer: 3000, showConfirmButton: false }); return; }
      setFormData({ ...formData, [name]: files[0] });
    }
  };

  const handleNuevaEmpresaChange = (e) => {
    const { name, value } = e.target;
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setNuevaEmpresa({ ...nuevaEmpresa, [parent]: { ...nuevaEmpresa[parent], [child]: value } });
    } else {
      setNuevaEmpresa({ ...nuevaEmpresa, [name]: value });
    }
  };

  const mostrarAlertaValidacion = (mensaje) => {
    Swal.fire({ icon: 'warning', title: 'Campo requerido', text: mensaje, timer: 3000, showConfirmButton: true, confirmButtonColor: '#00643C' });
  };

  const crearNuevaEmpresa = async () => {
    if (!nuevaEmpresa.nombre) return mostrarAlertaValidacion('El nombre de la empresa es obligatorio');
    if (!nuevaEmpresa.nit) return mostrarAlertaValidacion('El NIT es obligatorio');
    if (!nuevaEmpresa.fecha_creacion) return mostrarAlertaValidacion('La fecha de creación es obligatoria');
    if (!nuevaEmpresa.direccion) return mostrarAlertaValidacion('La dirección es obligatoria');
    if (!nuevaEmpresa.representante_legal.nombre_completo) return mostrarAlertaValidacion('El nombre del representante legal es obligatorio');
    if (!nuevaEmpresa.contacto.nombre_completo) return mostrarAlertaValidacion('El nombre del contacto es obligatorio');
    if (!nuevaEmpresa.contacto.telefono) return mostrarAlertaValidacion('El teléfono del contacto es obligatorio');
    if (!nuevaEmpresa.contacto.correo) return mostrarAlertaValidacion('El correo del contacto es obligatorio');
    if (!nuevaEmpresa.numero_empleados) return mostrarAlertaValidacion('El número de empleados es obligatorio');
    try {
      setLoading(true);
      const response = await api.post('/empresas', nuevaEmpresa);
      setEmpresas([...empresas, response.data.data]);
      setFormData({ ...formData, empresa_solicitante: response.data.data._id });
      setMostrarFormularioEmpresa(false);
      setNuevaEmpresa({ nombre: '', nit: '', fecha_creacion: '', tipo_empresa: 'Privada', direccion: '', representante_legal: { nombre_completo: '', documento_identidad: '', telefono: '', correo: '' }, contacto: { nombre_completo: '', cargo: '', telefono: '', correo: '' }, numero_empleados: '' });
      Swal.fire({ icon: 'success', title: '¡Empresa creada!', text: 'La empresa se ha registrado exitosamente', timer: 2000, showConfirmButton: false });
    } catch (error) {
      Swal.fire({ icon: 'error', title: 'Error', text: error.response?.data?.message || error.message, confirmButtonColor: '#e74c3c' });
    } finally { setLoading(false); }
  };

  const validarFormulario = () => {
    if (!formData.programa_formacion) return mostrarAlertaValidacion('Seleccione un programa de formación'), false;
    if (!formData.modalidad) return mostrarAlertaValidacion('Seleccione una modalidad'), false;
    if (!formData.tipo_oferta) return mostrarAlertaValidacion('Seleccione un tipo de oferta'), false;
    if (!formData.cupo_maximo) return mostrarAlertaValidacion('Ingrese el cupo máximo'), false;
    if (!formData.ambiente.nombre) return mostrarAlertaValidacion('El nombre del ambiente es obligatorio'), false;
    if (!formData.fechas.inicio || !formData.fechas.fin) return mostrarAlertaValidacion('Ingrese las fechas de inicio y fin'), false;
    if (new Date(formData.fechas.fin) <= new Date(formData.fechas.inicio)) { Swal.fire({ icon: 'warning', title: 'Fechas inválidas', text: 'La fecha de fin debe ser posterior a la de inicio', timer: 3000 }); return false; }
    if (!formData.ubicacion.municipio) return mostrarAlertaValidacion('Seleccione un municipio'), false;
    if (!formData.ubicacion.direccion) return mostrarAlertaValidacion('Ingrese la dirección'), false;
    if (!formData.empresa_solicitante) return mostrarAlertaValidacion('Seleccione una empresa solicitante'), false;
    if (!formData.subsector_economico.nombre) return mostrarAlertaValidacion('Ingrese el subsector económico'), false;
    if (!formData.convenio.nombre) return mostrarAlertaValidacion('El nombre del convenio es obligatorio'), false;
    if (modo === 'regular' && formData.horario.dias.length === 0) return mostrarAlertaValidacion('Seleccione al menos un día'), false;
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validarFormulario()) return;
    setLoading(true);
    try {
      const tipoProgramaId = modo === 'regular' ? tiposProgramaIds.regular : tiposProgramaIds.campesena;
      if (!tipoProgramaId) { Swal.fire({ icon: 'error', title: 'Error de configuración', text: 'No se encontró el ID del tipo de programa.', confirmButtonColor: '#e74c3c' }); setLoading(false); return; }
      const formDataToSend = new FormData();
      formDataToSend.append('programa_formacion', formData.programa_formacion);
      formDataToSend.append('modalidad', formData.modalidad);
      formDataToSend.append('tipo_oferta', formData.tipo_oferta);
      formDataToSend.append('cupo_maximo', formData.cupo_maximo);
      formDataToSend.append('empresa_solicitante', formData.empresa_solicitante);
      formDataToSend.append('programa_especial', formData.programa_especial || '');
      formDataToSend.append('tipo_programa', tipoProgramaId);
      formDataToSend.append('modo', modo);
      formDataToSend.append('ambiente_nombre', formData.ambiente.nombre);
      formDataToSend.append('fechas_inicio', formData.fechas.inicio);
      formDataToSend.append('fechas_fin', formData.fechas.fin);
      formDataToSend.append('ubicacion_departamento', formData.ubicacion.departamento);
      formDataToSend.append('ubicacion_municipio', formData.ubicacion.municipio);
      formDataToSend.append('ubicacion_direccion', formData.ubicacion.direccion);
      formDataToSend.append('subsector_nombre', formData.subsector_economico.nombre);
      formDataToSend.append('convenio_nombre', formData.convenio.nombre);
      if (modo === 'regular') { formDataToSend.append('horario_hora_inicio', formData.horario.hora_inicio); formDataToSend.append('horario_hora_fin', formData.horario.hora_fin); }
      formDataToSend.append('horario_dias', JSON.stringify(formData.horario.dias));
      formDataToSend.append('duracion_meses', '12');
      if (formData.firma_digital_pdf) formDataToSend.append('firma_digital_pdf', formData.firma_digital_pdf);
      if (formData.carta_pdf) formDataToSend.append('carta_pdf', formData.carta_pdf);
      if (modo === 'campesena' && formData.instructores) formDataToSend.append('instructores', JSON.stringify(formData.instructores));
      Swal.fire({ title: 'Guardando oferta...', text: 'Por favor espere', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
      await api.post('/ofertas', formDataToSend, { headers: { 'Content-Type': 'multipart/form-data' } });
      Swal.close();
      Swal.fire({ icon: 'success', title: '¡Oferta creada!', text: 'La oferta se ha guardado exitosamente', timer: 2000, showConfirmButton: false });
      setTimeout(() => window.location.reload(), 2000);
    } catch (error) {
      Swal.close();
      Swal.fire({ icon: 'error', title: 'Error', text: error.response?.data?.errors?.join(', ') || error.response?.data?.message || error.message, confirmButtonColor: '#e74c3c' });
    } finally { setLoading(false); }
  };

  const diasSemana = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

  if (!modo) return <SeleccionarTipoOferta onSeleccionar={setModo} />;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;500;600&display=swap');

        .co-page {
          font-family: 'Sora', sans-serif;
          background: #f4f7f5;
          min-height: 100vh;
          padding: 40px 24px;
          box-sizing: border-box;
        }

        .co-card {
          background: #fff;
          border: 1px solid #e0ebe4;
          border-radius: 20px;
          width: 100%;
          max-width: 760px;
          margin: 0 auto;
          padding: 44px 40px;
          position: relative;
          box-sizing: border-box;
        }

        .co-card::before {
          content: '';
          position: absolute;
          top: -1px; left: 50%; transform: translateX(-50%);
          width: 160px; height: 3px;
          background: #00643C;
          border-radius: 0 0 4px 4px;
        }

        .co-top {
          display: flex;
          align-items: center;
          justify-content: space-between;
          margin-bottom: 32px;
        }

        .co-logo {
          background: #00643C;
          border-radius: 10px;
          padding: 8px 14px;
          font-size: 15px;
          font-weight: 600;
          color: white;
          letter-spacing: 2px;
        }

        .co-mode-badge {
          display: flex;
          align-items: center;
          gap: 6px;
          font-size: 12px;
          font-weight: 500;
          padding: 5px 12px;
          border-radius: 20px;
          border: 1px solid #dce8e1;
          background: #f0f7f3;
          color: #00643C;
        }

        .co-mode-dot {
          width: 7px; height: 7px;
          border-radius: 50%;
          background: #00a661;
        }

        .co-heading {
          font-size: 20px;
          font-weight: 600;
          color: #111;
          margin: 0 0 4px 0;
        }

        .co-sub {
          font-size: 13px;
          color: #7a8f82;
          margin: 0 0 28px 0;
        }

        .co-back-btn {
          background: transparent;
          border: 1px solid #dce8e1;
          border-radius: 8px;
          padding: 7px 14px;
          font-size: 12px;
          font-family: 'Sora', sans-serif;
          color: #7a8f82;
          cursor: pointer;
          transition: background 0.2s;
        }
        .co-back-btn:hover { background: #f0f7f3; }

        .co-section {
          margin-bottom: 28px;
        }

        .co-section-label {
          font-size: 10px;
          font-weight: 600;
          letter-spacing: 1.5px;
          text-transform: uppercase;
          color: #00643C;
          margin: 0 0 14px 0;
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .co-section-label::after {
          content: ''; flex: 1; height: 1px; background: #e8f0eb;
        }

        .co-row {
          display: flex;
          gap: 14px;
          margin-bottom: 14px;
        }

        .co-half { flex: 1; }

        .co-field {
          margin-bottom: 14px;
        }

        .co-label {
          display: block;
          font-size: 11px;
          font-weight: 500;
          letter-spacing: 0.8px;
          text-transform: uppercase;
          color: #7a8f82;
          margin-bottom: 6px;
        }

        .co-input, .co-select {
          width: 100%;
          padding: 11px 14px;
          background: #f8faf9;
          border: 1px solid #dce8e1;
          border-radius: 10px;
          font-size: 13px;
          font-family: 'Sora', sans-serif;
          color: #111;
          outline: none;
          box-sizing: border-box;
          transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
        }

        .co-input::placeholder { color: #b8ccc0; }

        .co-input:focus, .co-select:focus {
          border-color: #00643C;
          background: white;
          box-shadow: 0 0 0 3px rgba(0,100,60,0.08);
        }

        .co-select { appearance: none; cursor: pointer; }

        .co-days {
          display: flex;
          flex-wrap: wrap;
          gap: 8px;
          margin-top: 4px;
        }

        .co-day-label {
          display: flex;
          align-items: center;
          gap: 6px;
          padding: 7px 13px;
          border: 1px solid #dce8e1;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 500;
          color: #5a7060;
          background: #f8faf9;
          cursor: pointer;
          transition: all 0.15s;
          user-select: none;
        }

        .co-day-label input { display: none; }
        .co-day-label.checked {
          background: #00643C;
          border-color: #00643C;
          color: white;
        }

        .co-file-box {
          border: 1.5px dashed #dce8e1;
          border-radius: 10px;
          padding: 14px 16px;
          background: #f8faf9;
          cursor: pointer;
          transition: border-color 0.2s;
          position: relative;
        }

        .co-file-box:hover { border-color: #00643C; }

        .co-file-box input {
          position: absolute; inset: 0; opacity: 0; cursor: pointer; width: 100%; height: 100%;
        }

        .co-file-info {
          display: flex;
          align-items: center;
          gap: 10px;
        }

        .co-file-icon {
          width: 32px; height: 32px;
          background: #e8f0eb;
          border-radius: 8px;
          display: flex; align-items: center; justify-content: center;
          font-size: 14px;
          flex-shrink: 0;
        }

        .co-file-text { font-size: 12px; color: #7a8f82; }
        .co-file-name { font-size: 13px; color: #111; font-weight: 500; }

        .co-remove-file {
          margin-left: auto;
          background: transparent;
          border: none;
          color: #e74c3c;
          font-size: 16px;
          cursor: pointer;
          padding: 0 4px;
          flex-shrink: 0;
        }

        .co-sub-card {
          background: #f8faf9;
          border: 1px solid #e0ebe4;
          border-radius: 12px;
          padding: 20px;
          margin-top: 8px;
        }

        .co-sub-section {
          font-size: 10px;
          font-weight: 600;
          letter-spacing: 1.2px;
          text-transform: uppercase;
          color: #00643C;
          margin: 16px 0 10px 0;
        }

        .co-add-btn {
          width: 100%;
          padding: 11px;
          background: transparent;
          border: 1.5px dashed #dce8e1;
          border-radius: 10px;
          font-size: 13px;
          font-family: 'Sora', sans-serif;
          color: #00643C;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.2s;
          margin-top: 4px;
        }
        .co-add-btn:hover { background: #f0f7f3; border-color: #00643C; }

        .co-btn-row {
          display: flex;
          gap: 12px;
          margin-top: 28px;
        }

        .co-btn-primary {
          flex: 2;
          padding: 14px;
          background: #00643C;
          color: white;
          border: none;
          border-radius: 10px;
          font-size: 14px;
          font-weight: 600;
          font-family: 'Sora', sans-serif;
          cursor: pointer;
          transition: background 0.2s, transform 0.1s;
        }
        .co-btn-primary:hover:not(:disabled) { background: #004d2e; }
        .co-btn-primary:active:not(:disabled) { transform: scale(0.99); }
        .co-btn-primary:disabled { background: #a3c4b5; cursor: not-allowed; }

        .co-btn-secondary {
          flex: 1;
          padding: 14px;
          background: transparent;
          color: #00643C;
          border: 1px solid #dce8e1;
          border-radius: 10px;
          font-size: 14px;
          font-weight: 500;
          font-family: 'Sora', sans-serif;
          cursor: pointer;
          transition: background 0.2s;
        }
        .co-btn-secondary:hover { background: #f0f7f3; }

        .co-btn-danger {
          flex: 1;
          padding: 11px;
          background: transparent;
          color: #e74c3c;
          border: 1px solid #fca5a5;
          border-radius: 10px;
          font-size: 13px;
          font-weight: 500;
          font-family: 'Sora', sans-serif;
          cursor: pointer;
          transition: background 0.2s;
        }
        .co-btn-danger:hover { background: #fef2f2; }

        .co-save-empresa-btn {
          flex: 2;
          padding: 11px;
          background: #00643C;
          color: white;
          border: none;
          border-radius: 10px;
          font-size: 13px;
          font-weight: 600;
          font-family: 'Sora', sans-serif;
          cursor: pointer;
        }
        .co-save-empresa-btn:disabled { background: #a3c4b5; cursor: not-allowed; }

        .co-footer {
          margin-top: 32px;
          padding-top: 18px;
          border-top: 1px solid #e8f0eb;
          text-align: center;
          font-size: 11px;
          color: #b8ccc0;
        }

        @media (max-width: 600px) {
          .co-card { padding: 32px 20px; }
          .co-row { flex-direction: column; gap: 0; }
          .co-half { margin-bottom: 14px; }
          .co-btn-row { flex-direction: column; }
        }
      `}</style>

      <div className="co-page">
        <div className="co-card">

          <div className="co-top">
            <div className="co-logo">SENA</div>
            <div className="co-mode-badge">
              <div className="co-mode-dot" />
              {modo === 'regular' ? 'Oferta Regular' : 'Oferta Campesena'}
            </div>
          </div>

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '28px' }}>
            <div>
              <h2 className="co-heading">Crear nueva oferta</h2>
              <p className="co-sub">Completa los campos para registrar la oferta en la plataforma.</p>
            </div>
            <button className="co-back-btn" onClick={() => setModo(null)}>← Cambiar tipo</button>
          </div>

          <form onSubmit={handleSubmit}>

            {/* PROGRAMA */}
            <div className="co-section">
              <div className="co-section-label">Programa de formación</div>
              <div className="co-field">
                <label className="co-label">Programa</label>
                <select className="co-select" name="programa_formacion" value={formData.programa_formacion} onChange={handleChange} required>
                  <option value="">Seleccione...</option>
                  {programas.map(p => <option key={p._id} value={p._id}>{p.nombre_programa} — {p.codigo}</option>)}
                </select>
              </div>
              <div className="co-row">
                <div className="co-half">
                  <label className="co-label">Modalidad</label>
                  <select className="co-select" name="modalidad" value={formData.modalidad} onChange={handleChange} required>
                    <option value="">Seleccione...</option>
                    {modalidades.map(m => <option key={m._id} value={m._id}>{m.nombre}</option>)}
                  </select>
                </div>
                <div className="co-half">
                  <label className="co-label">Tipo de oferta</label>
                  <select className="co-select" name="tipo_oferta" value={formData.tipo_oferta} onChange={handleChange} required>
                    <option value="">Seleccione...</option>
                    {tiposOferta.map(t => <option key={t._id} value={t._id}>{t.nombre}</option>)}
                  </select>
                </div>
              </div>
              <div className="co-field">
                <label className="co-label">Cupo máximo</label>
                <input className="co-input" type="number" name="cupo_maximo" value={formData.cupo_maximo} onChange={handleChange} placeholder="30" min="1" required />
              </div>
            </div>

            {/* AMBIENTE Y FECHAS */}
            <div className="co-section">
              <div className="co-section-label">Ambiente y fechas</div>
              <div className="co-field">
                <label className="co-label">Nombre del ambiente</label>
                <input className="co-input" type="text" name="ambiente.nombre" value={formData.ambiente.nombre} onChange={handleChange} placeholder="Ej: Aula 101" required />
              </div>
              <div className="co-row">
                <div className="co-half">
                  <label className="co-label">Fecha inicio</label>
                  <input className="co-input" type="date" name="fechas.inicio" value={formData.fechas.inicio} onChange={handleChange} required />
                </div>
                <div className="co-half">
                  <label className="co-label">Fecha fin</label>
                  <input className="co-input" type="date" name="fechas.fin" value={formData.fechas.fin} onChange={handleChange} required />
                </div>
              </div>
            </div>

            {/* UBICACIÓN */}
            <div className="co-section">
              <div className="co-section-label">Ubicación</div>
              <div className="co-row">
                <div className="co-half">
                  <label className="co-label">Departamento</label>
                  <input className="co-input" type="text" name="ubicacion.departamento" value={formData.ubicacion.departamento} onChange={handleChange} placeholder="Cauca" required />
                </div>
                <div className="co-half">
                  <label className="co-label">Municipio</label>
                  <select className="co-select" name="ubicacion.municipio" value={formData.ubicacion.municipio} onChange={handleChange} required>
                    <option value="">Seleccione...</option>
                    {municipios.map(m => <option key={m._id} value={m._id}>{m.nombre}</option>)}
                  </select>
                </div>
              </div>
              <div className="co-field">
                <label className="co-label">Dirección</label>
                <input className="co-input" type="text" name="ubicacion.direccion" value={formData.ubicacion.direccion} onChange={handleChange} placeholder="Calle 123 #45-67, Barrio Centro" required />
              </div>
            </div>

            {/* EMPRESA */}
            <div className="co-section">
              <div className="co-section-label">Empresa solicitante</div>
              {!mostrarFormularioEmpresa ? (
                <>
                  <div className="co-field">
                    <label className="co-label">Seleccionar empresa</label>
                    <select className="co-select" name="empresa_solicitante" value={formData.empresa_solicitante} onChange={handleChange} required>
                      <option value="">Seleccione una empresa...</option>
                      {empresas.map(e => <option key={e._id} value={e._id}>{e.nombre} — NIT: {e.nit}</option>)}
                    </select>
                  </div>
                  <button type="button" className="co-add-btn" onClick={() => setMostrarFormularioEmpresa(true)}>+ Registrar nueva empresa</button>
                </>
              ) : (
                <div className="co-sub-card">
                  <div className="co-sub-section">Datos básicos</div>
                  <div className="co-field">
                    <label className="co-label">Nombre de la empresa</label>
                    <input className="co-input" type="text" name="nombre" value={nuevaEmpresa.nombre} onChange={handleNuevaEmpresaChange} placeholder="Nombre de la empresa" />
                  </div>
                  <div className="co-row">
                    <div className="co-half">
                      <label className="co-label">NIT</label>
                      <input className="co-input" type="text" name="nit" value={nuevaEmpresa.nit} onChange={handleNuevaEmpresaChange} placeholder="123456789-0" />
                    </div>
                    <div className="co-half">
                      <label className="co-label">Fecha creación</label>
                      <input className="co-input" type="date" name="fecha_creacion" value={nuevaEmpresa.fecha_creacion} onChange={handleNuevaEmpresaChange} />
                    </div>
                  </div>
                  <div className="co-row">
                    <div className="co-half">
                      <label className="co-label">Tipo de empresa</label>
                      <select className="co-select" name="tipo_empresa" value={nuevaEmpresa.tipo_empresa} onChange={handleNuevaEmpresaChange}>
                        {['Privada','Pública','Mixta','ONG','Fundación','Cooperativa','Otro'].map(t => <option key={t}>{t}</option>)}
                      </select>
                    </div>
                    <div className="co-half">
                      <label className="co-label">Dirección</label>
                      <input className="co-input" type="text" name="direccion" value={nuevaEmpresa.direccion} onChange={handleNuevaEmpresaChange} placeholder="Dirección completa" />
                    </div>
                  </div>

                  <div className="co-sub-section">Representante legal</div>
                  <div className="co-field">
                    <label className="co-label">Nombre completo</label>
                    <input className="co-input" type="text" name="representante_legal.nombre_completo" value={nuevaEmpresa.representante_legal.nombre_completo} onChange={handleNuevaEmpresaChange} placeholder="Nombre del representante" />
                  </div>
                  <div className="co-row">
                    <div className="co-half">
                      <label className="co-label">Documento</label>
                      <input className="co-input" type="text" name="representante_legal.documento_identidad" value={nuevaEmpresa.representante_legal.documento_identidad} onChange={handleNuevaEmpresaChange} placeholder="Documento" />
                    </div>
                    <div className="co-half">
                      <label className="co-label">Teléfono</label>
                      <input className="co-input" type="text" name="representante_legal.telefono" value={nuevaEmpresa.representante_legal.telefono} onChange={handleNuevaEmpresaChange} placeholder="Teléfono" />
                    </div>
                  </div>
                  <div className="co-field">
                    <label className="co-label">Correo</label>
                    <input className="co-input" type="email" name="representante_legal.correo" value={nuevaEmpresa.representante_legal.correo} onChange={handleNuevaEmpresaChange} placeholder="correo@ejemplo.com" />
                  </div>

                  <div className="co-sub-section">Contacto en la empresa</div>
                  <div className="co-field">
                    <label className="co-label">Nombre completo</label>
                    <input className="co-input" type="text" name="contacto.nombre_completo" value={nuevaEmpresa.contacto.nombre_completo} onChange={handleNuevaEmpresaChange} placeholder="Nombre del contacto" />
                  </div>
                  <div className="co-row">
                    <div className="co-half">
                      <label className="co-label">Cargo</label>
                      <input className="co-input" type="text" name="contacto.cargo" value={nuevaEmpresa.contacto.cargo} onChange={handleNuevaEmpresaChange} placeholder="Cargo" />
                    </div>
                    <div className="co-half">
                      <label className="co-label">Teléfono</label>
                      <input className="co-input" type="text" name="contacto.telefono" value={nuevaEmpresa.contacto.telefono} onChange={handleNuevaEmpresaChange} placeholder="Teléfono" />
                    </div>
                  </div>
                  <div className="co-row">
                    <div className="co-half">
                      <label className="co-label">Correo</label>
                      <input className="co-input" type="email" name="contacto.correo" value={nuevaEmpresa.contacto.correo} onChange={handleNuevaEmpresaChange} placeholder="correo@ejemplo.com" />
                    </div>
                    <div className="co-half">
                      <label className="co-label">N° de empleados</label>
                      <input className="co-input" type="number" name="numero_empleados" value={nuevaEmpresa.numero_empleados} onChange={handleNuevaEmpresaChange} placeholder="Ej: 50" min="1" />
                    </div>
                  </div>

                  <div className="co-btn-row" style={{ marginTop: '16px' }}>
                    <button type="button" className="co-save-empresa-btn" onClick={crearNuevaEmpresa} disabled={loading}>{loading ? 'Guardando...' : 'Guardar empresa'}</button>
                    <button type="button" className="co-btn-danger" onClick={() => setMostrarFormularioEmpresa(false)}>Cancelar</button>
                  </div>
                </div>
              )}
            </div>

            {/* SUBSECTOR Y CONVENIO */}
            <div className="co-section">
              <div className="co-section-label">Información adicional</div>
              <div className="co-row">
                <div className="co-half">
                  <label className="co-label">Subsector económico</label>
                  <input className="co-input" type="text" name="subsector_economico.nombre" value={formData.subsector_economico.nombre} onChange={handleChange} placeholder="Ej: Tecnologías de la Información" required />
                </div>
                <div className="co-half">
                  <label className="co-label">Nombre del convenio</label>
                  <input className="co-input" type="text" name="convenio.nombre" value={formData.convenio.nombre} onChange={handleChange} placeholder="Nombre del convenio" required />
                </div>
              </div>
              <div className="co-field">
                <label className="co-label">Programa especial (opcional)</label>
                <select className="co-select" name="programa_especial" value={formData.programa_especial} onChange={handleChange}>
                  <option value="">Ninguno</option>
                  {programasEspeciales.map(pe => <option key={pe._id} value={pe._id}>{pe.nombre}</option>)}
                </select>
              </div>
            </div>

            {/* HORARIO — solo Regular */}
            {modo === 'regular' && (
              <div className="co-section">
                <div className="co-section-label">Horario</div>
                <div className="co-row">
                  <div className="co-half">
                    <label className="co-label">Hora inicio</label>
                    <input className="co-input" type="time" name="horario.hora_inicio" value={formData.horario.hora_inicio} onChange={handleChange} required />
                  </div>
                  <div className="co-half">
                    <label className="co-label">Hora fin</label>
                    <input className="co-input" type="time" name="horario.hora_fin" value={formData.horario.hora_fin} onChange={handleChange} required />
                  </div>
                </div>
                <div className="co-field">
                  <label className="co-label">Días</label>
                  <div className="co-days">
                    {diasSemana.map(dia => (
                      <label key={dia} className={`co-day-label${formData.horario.dias.includes(dia) ? ' checked' : ''}`}>
                        <input type="checkbox" value={dia} checked={formData.horario.dias.includes(dia)} onChange={handleDiaChange} />
                        {dia}
                      </label>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* CAMPESENA */}
            {modo === 'campesena' && (
              <FormularioCampesenaCompleto formData={formData} setFormData={setFormData} />
            )}

            {/* DOCUMENTOS */}
            <div className="co-section">
              <div className="co-section-label">Documentos adjuntos</div>
              <div className="co-field">
                <label className="co-label">Firma digital (PDF)</label>
                <div className="co-file-box">
                  <input type="file" id="firma_digital_pdf" name="firma_digital_pdf" onChange={handleFileChange} accept=".pdf" />
                  <div className="co-file-info">
                    <div className="co-file-icon">📄</div>
                    {formData.firma_digital_pdf
                      ? <><span className="co-file-name">{formData.firma_digital_pdf.name}</span><button type="button" className="co-remove-file" onClick={() => { document.getElementById('firma_digital_pdf').value = ''; setFormData({...formData, firma_digital_pdf: null}); }}>✕</button></>
                      : <span className="co-file-text">Haz clic para adjuntar firma digital en PDF</span>}
                  </div>
                </div>
              </div>
              <div className="co-field">
                <label className="co-label">Carta (PDF)</label>
                <div className="co-file-box">
                  <input type="file" id="carta_pdf" name="carta_pdf" onChange={handleFileChange} accept=".pdf" />
                  <div className="co-file-info">
                    <div className="co-file-icon">📋</div>
                    {formData.carta_pdf
                      ? <><span className="co-file-name">{formData.carta_pdf.name}</span><button type="button" className="co-remove-file" onClick={() => { document.getElementById('carta_pdf').value = ''; setFormData({...formData, carta_pdf: null}); }}>✕</button></>
                      : <span className="co-file-text">Haz clic para adjuntar carta en PDF</span>}
                  </div>
                </div>
              </div>
            </div>

            <div className="co-btn-row">
              <button type="submit" className="co-btn-primary" disabled={loading}>{loading ? 'Guardando...' : 'Guardar oferta'}</button>
              <button type="button" className="co-btn-secondary" onClick={() => setModo(null)}>Cancelar</button>
            </div>

          </form>

          <div className="co-footer">© 2025 SENA · Servicio Nacional de Aprendizaje</div>
        </div>
      </div>
    </>
  );
};

export default CrearOferta;
